parameters.jsCode:
// =====================================================================
// BuildConfig (paste-safe v3)
//
// Inputs: a single merged stream from Setup_Merge (mode: append) carrying
//   rows from 6 Google Sheets tabs: Setup, RoomRanks, SOPExamples,
//   CommentGlossary, Memberships, Actions. Each tab's rows keep their
//   original column shape — the first non-"row_number" key is the sheet's
//   title column, which we use to identify which tab a row came from.
//
// Output: one JSON object consumed by every downstream node.
//
// Written WITHOUT any "\n" or "\\|" escapes — those get eaten when the
// SDK round-trips this code, which is what broke the previous version.
// Uses array.join() with a precomputed newline constant instead.
// =====================================================================

const NL = String.fromCharCode(10);  // newline, no escape needed
const PIPE = String.fromCharCode(124); // |

// ---------- Helpers ----------
const yn = v => String(v == null ? "" : v).trim().toUpperCase().startsWith("Y");
const num = v => {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(String(v).replace(/[, ]/g, ""));
  return Number.isFinite(n) ? n : null;
};

// Return the row's "logical column" values, skipping the row_number metadata
// column. The first item is the sheet's title column, then col_2, col_3, ...
function logicalCols(row) {
  const keys = Object.keys(row).filter(k => k !== "row_number");
  return keys.map(k => row[k] == null ? "" : String(row[k]));
}

// Skip rows that aren't real data. Every Google Sheets tab in this workbook
// has the same shape:
//   row 1 = title (becomes the column header in n8n's output)
//   row 2 = intro paragraph (long text in col 0, other cols empty)
//   row 3 = blank
//   row 4 = column headers (e.g. "Comment Example", "Assign Attribute", ...)
//   row 5+ = real data
//
// We can't trust row_number alone (a user may add rows). So we filter by
// shape: a row is "header-or-intro" if col 0 matches one of the known column
// header strings for any tab, or if col 0 is very long (> 60 chars) AND
// every other column is empty.
const HEADER_STRINGS = new Set([
  "feature", "parameter",
  "rank", "room type id",
  "comment example",
  "phrase",
  "membership level",
  "action",
]);
function isHeaderOrIntro(v) {
  const c0 = (v[0] || "").trim();
  if (!c0) return true;
  if (HEADER_STRINGS.has(c0.toLowerCase())) return true;
  // Intro paragraph: long prose in col 0 with all other cells empty
  if (c0.length > 60) {
    const rest = v.slice(1).map(x => (x || "").trim());
    if (rest.every(x => x === "")) return true;
  }
  return false;
}

// First (title) key for the row, lowercased, for classification.
function titleKey(row) {
  const keys = Object.keys(row).filter(k => k !== "row_number");
  return (keys[0] || "").toLowerCase();
}

// Classify a single row by its title column header.
function classifyRow(row) {
  const t = titleKey(row);
  if (!t) return "Unknown";
  if (t.indexOf("room allocation agent") !== -1 || t === "setup") return "Setup";
  if (t.indexOf("room type rank") !== -1 || t === "roomranks")    return "RoomRanks";
  if (t.indexOf("property-specific sop") !== -1 || t.indexOf("comment pattern") !== -1 || t === "sopexamples") return "SOPExamples";
  if (t.indexOf("comment glossary") !== -1 || t === "commentglossary" || t === "glossary") return "CommentGlossary";
  if (t.indexOf("membership") !== -1 || t === "memberships")      return "Memberships";
  if (t.indexOf("allowed agent action") !== -1 || t === "actions") return "Actions";
  return "Unknown";
}

// ---------- Collect all rows from the merged stream ----------
const allRows = $input.all().map(it => it.json);

// Bucket every row by its detected sheet
const buckets = { Setup: [], RoomRanks: [], SOPExamples: [], CommentGlossary: [], Memberships: [], Actions: [], Unknown: [] };
for (const row of allRows) buckets[classifyRow(row)].push(row);

// ---------- Parse Setup tab ----------
const FEATURE_KEYS = {
  "critical attribute":           "critical",
  "adjacency":                    "adjacency",
  "preference attribute":         "preference",
  "booking-group proximity":      "groupProximity",
  "floor preference":             "floorPreference",
  "upgrade quality":              "upgrade",
  "early check-in":               "eci",
  "anschlussbuchung":             "asb",
  "legionella":                   "legionella",
  "room condition":               "roomCondition",
};
function matchFeatureKey(name) {
  const lower = String(name == null ? "" : name).toLowerCase();
  for (const needle of Object.keys(FEATURE_KEYS)) {
    if (lower.indexOf(needle) !== -1) return FEATURE_KEYS[needle];
  }
  return null;
}

const flags = {};
const params = {};
for (const row of buckets.Setup) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const label = (v[0] || "").trim();
  if (!label) continue;
  const featKey = matchFeatureKey(label);
  if (featKey) {
    flags[featKey] = { enabled: yn(v[1]), priority: num(v[2]) };
    continue;
  }
  // Parameter rows: label is snake_case
  if (/^[a-z][a-z0-9_]+$/.test(label)) {
    params[label] = v[1];
  }
}

// ---------- Internal tuning knobs ----------
const TUNING = {
  priorityDecayExponent:     0.7,
  priorityDecayBaseWeight:   1.0,
  floorPrefBonusPerStep:     15,
  legionellaAssignmentBonus: 800,
  eciDirtyExtraPenalty:      400,
};
const decayExp = TUNING.priorityDecayExponent;
const baseW    = TUNING.priorityDecayBaseWeight;

function priorityMultiplier(rank) {
  const r = Number(rank);
  if (!Number.isFinite(r) || r <= 0) return baseW;
  return baseW / Math.pow(r, decayExp);
}

const featureConfig = {};
for (const k of Object.values(FEATURE_KEYS)) {
  const f = flags[k];
  if (!f) {
    featureConfig[k] = { enabled: true, priority: null, multiplier: baseW };
  } else {
    featureConfig[k] = {
      enabled:  f.enabled,
      priority: f.priority,
      multiplier: f.enabled ? priorityMultiplier(f.priority) : 0,
    };
  }
}

// ---------- Parse RoomRanks ----------
const ranks = [];
for (const row of buckets.RoomRanks) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const rank = num(v[0]);
  const id   = (v[1] || "").trim();
  if (rank === null || !id) continue;
  ranks.push({
    rank,
    id,
    name: (v[2] || "").trim() || null,
    protectedSuite: yn(v[3]),
  });
}

// ---------- Parse SOPExamples ----------
const sopExamples = [];
for (const row of buckets.SOPExamples) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const ce = (v[0] || "").trim();
  if (!ce) continue;
  sopExamples.push({
    commentExample:  ce,
    assignAttribute: (v[1] || "").trim(),
    actionTake:      (v[2] || "").trim(),
    actionAvoid:     (v[3] || "").trim(),
  });
}

// ---------- Parse CommentGlossary ----------
const glossary = [];
for (const row of buckets.CommentGlossary) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const phrase = (v[0] || "").trim();
  if (!phrase) continue;
  glossary.push({
    phrase,
    meaning:        (v[1] || "").trim(),
    triggersAction: (v[2] || "").trim(),
    notes:          (v[3] || "").trim(),
  });
}

// ---------- Parse Memberships ----------
const memberships = [];
for (const row of buckets.Memberships) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const level = (v[0] || "").trim();
  const action = (v[2] || "").trim();
  const mode = (v[3] || "").trim();
  if (!level || !action || !mode) continue;
  const triggers = (v[1] || "").split(",").map(s => s.trim()).filter(Boolean);
  memberships.push({ level, triggers, action, mode, notes: (v[4] || "").trim() });
}

// ---------- Parse Actions ----------
const actions = [];
for (const row of buckets.Actions) {
  const v = logicalCols(row);
  if (isHeaderOrIntro(v)) continue;
  const action = (v[0] || "").trim();
  if (!action) continue;
  actions.push({
    action,
    description:   (v[1] || "").trim(),
    allowedModes:  (v[2] || "").trim(),
    triggeredBy:   (v[3] || "").trim(),
    scoringEffect: (v[4] || "").trim(),
  });
}

// ---------- Global params ----------
const legionellaMaxDays       = num(params.legionella_max_vacancy_days) != null ? num(params.legionella_max_vacancy_days) : 3;
const optionalUpgradesAllowed = yn(params.optional_upgrades_allowed == null ? "Y" : params.optional_upgrades_allowed);
const propertyId              = String(params.property_id == null ? "" : params.property_id).trim() || null;
const assignForDayRaw         = String(params.assign_for_day == null ? "today" : params.assign_for_day).trim().toLowerCase();
const assignForDay            = assignForDayRaw === "tomorrow" ? "tomorrow" : "today";
const assignDayOffset         = assignForDay === "tomorrow" ? 1 : 0;

// ---------- Baseline weights ----------
const BASELINE = {
  critSat:   240, critUnsat: -420, critCap: -1200,
  prefSat:    90, prefUnsat: -140, prefCap:  -600,
  adjForcedByDist: { "0": 320, "1": 210, "2": 80, "3+": -280 },
  adjOptByDist:    { "0": 120, "1":  80, "2": 30, "3+":  -60 },
  bookProxByDist:  { "0": 140, "1": 110, "2": 70, "3":  30, "4+": -40 },
  bookProxCapGlobal: 1600,
  adjForcedCap: 1600,
  adjOptCap:     600,
  upgradeGood:    80, upgradeNeutral: 10, upgradeBad: -120, upgradeCap: 200,
  roomState: { clean: 80, inspect: 20, dirty: -120, tomorrow: -260, occupied: -350 },
  allForcedAdjBonus: 500,
  groupClusterBonus: 220,
  unassignedPenalty: -250000,
  hardConstraintPenalty: -1000000,
};

const W = featureConfig;
function scale(featKey, value) {
  const m = (W[featKey] && W[featKey].multiplier) != null ? W[featKey].multiplier : 1;
  return Math.round(value * m);
}

const scaled = {
  critSat:   scale("critical", BASELINE.critSat),
  critUnsat: scale("critical", BASELINE.critUnsat),
  critCap:   scale("critical", BASELINE.critCap),
  prefSat:   scale("preference", BASELINE.prefSat),
  prefUnsat: scale("preference", BASELINE.prefUnsat),
  prefCap:   scale("preference", BASELINE.prefCap),
  adjForcedByDist:   Object.fromEntries(Object.entries(BASELINE.adjForcedByDist).map(([k, v]) => [k, scale("adjacency", v)])),
  adjOptByDist:      Object.fromEntries(Object.entries(BASELINE.adjOptByDist).map(([k, v]) => [k, scale("adjacency", v)])),
  adjForcedCap:      scale("adjacency", BASELINE.adjForcedCap),
  adjOptCap:         scale("adjacency", BASELINE.adjOptCap),
  allForcedAdjBonus: scale("adjacency", BASELINE.allForcedAdjBonus),
  bookProxByDist:    Object.fromEntries(Object.entries(BASELINE.bookProxByDist).map(([k, v]) => [k, scale("groupProximity", v)])),
  bookProxCapGlobal: scale("groupProximity", BASELINE.bookProxCapGlobal),
  groupClusterBonus: scale("groupProximity", BASELINE.groupClusterBonus),
  upgradeGood:       scale("upgrade", BASELINE.upgradeGood),
  upgradeNeutral:    scale("upgrade", BASELINE.upgradeNeutral),
  upgradeBad:        scale("upgrade", BASELINE.upgradeBad),
  upgradeCap:        scale("upgrade", BASELINE.upgradeCap),
  roomState:         Object.fromEntries(Object.entries(BASELINE.roomState).map(([k, v]) => [k, scale("roomCondition", v)])),
  floorPrefBonusPerStep:     scale("floorPreference", TUNING.floorPrefBonusPerStep),
  legionellaAssignmentBonus: scale("legionella",      TUNING.legionellaAssignmentBonus),
  eciDirtyExtraPenalty:      scale("eci",             TUNING.eciDirtyExtraPenalty),
  unassignedPenalty:     BASELINE.unassignedPenalty,
  hardConstraintPenalty: BASELINE.hardConstraintPenalty,
};

// ---------- Markdown table builders (no "\n" in string literals) ----------
function escapeCell(s) {
  // Strip pipes and any newline-class chars without using \n escapes in source
  return String(s == null ? "" : s)
    .split(PIPE).join("/")
    .split("\r").join(" ")
    .split(String.fromCharCode(10)).join(" ")
    .trim();
}

function buildMd(headers, rows) {
  const lines = [];
  lines.push(PIPE + " " + headers.join(" " + PIPE + " ") + " " + PIPE);
  lines.push(PIPE + " " + headers.map(() => "---").join(" " + PIPE + " ") + " " + PIPE);
  for (const r of rows) {
    lines.push(PIPE + " " + r.map(escapeCell).join(" " + PIPE + " ") + " " + PIPE);
  }
  return lines.join(NL);
}

const sopTableMarkdown = buildMd(
  ["Comment Example", "Assign Attribute", "Action to take", "Action NOT to take"],
  sopExamples.map(r => [r.commentExample, r.assignAttribute, r.actionTake, r.actionAvoid])
);

const glossaryTableMarkdown = buildMd(
  ["Phrase", "Meaning", "Triggers Action", "Notes"],
  glossary.map(g => [g.phrase, g.meaning, g.triggersAction, g.notes])
);

const membershipsTableMarkdown = buildMd(
  ["Membership Level", "Recognise in comment as", "Action", "Mode", "Notes"],
  memberships.map(m => [m.level, m.triggers.join(", "), m.action, m.mode, m.notes])
);

const actionsTableMarkdown = buildMd(
  ["Action", "What it means", "Allowed Modes", "Triggered by"],
  actions.map(a => [a.action, a.description, a.allowedModes, a.triggeredBy])
);

// ---------- Output ----------
return [{
  json: {
    features:                  featureConfig,
    weights:                   scaled,
    legionellaMaxDays,
    optionalUpgradesAllowed,
    propertyId,
    assignForDay,
    assignDayOffset,
    decayExp,
    baseWeight: baseW,
    roomTypeRanks:             ranks,
    protectedSuiteRanks:       ranks.filter(r => r.protectedSuite).map(r => r.rank),
    sopExamples,
    sopTableMarkdown,
    glossary,
    glossaryTableMarkdown,
    memberships,
    membershipsTableMarkdown,
    actions,
    actionsTableMarkdown,
    rawParams: params,
    _debug: {
      bucketCounts: Object.fromEntries(Object.entries(buckets).map(([k, v]) => [k, v.length])),
      sampleTitles: allRows.slice(0, 10).map(r => titleKey(r)),
    },
  }
}];

const reservations = $input.first().json.reservations;
const assignments = reservations.filter(r => r.assignedUnits && r.assignedUnits.length > 0).map(r => ({ id: r.id, unitId: r.assignedUnits[0].unit.id, roomName: r.assignedUnits[0].unit.name }));
return [{ json: { assignments } }];

parameters.text:
=Unassign every reservation in the list below by calling the unassign unit tool for each one. Work through them sequentially, one by one, using the id field as the reservation ID. Continue until all reservations have been processed.

Reservations to unassign:
{{ JSON.stringify($json.assignments) }}

parameters.jsCode:
const items = $input.all();
const reservations = [];
for (const item of items) {
  if (Array.isArray(item.json.reservations)) {
    reservations.push(...item.json.reservations);
  }
}

const cfg = (() => {
  try { return $('BuildConfig').first().json; }
  catch (_) { return {}; }
})();
const LEGIONELLA_MAX_DAYS = Number(cfg.legionellaMaxDays ?? 3);
const ASSIGN_DAY_OFFSET   = Number(cfg.assignDayOffset ?? 0);

const toDateOnly = (iso) => iso.split('T')[0];

function daysBetween(a, b) { return Math.round((new Date(b) - new Date(a)) / 86400000); }
function addDays(dateStr, n) { const d = new Date(dateStr); d.setDate(d.getDate() + n); return toDateOnly(d.toISOString()); }

const now = new Date();
const realToday = toDateOnly(now.toISOString());
const todayStr  = addDays(realToday, ASSIGN_DAY_OFFSET);
const windowEnd = addDays(todayStr, 6);

const roomMap = {};
for (const r of reservations) {
  const roomId = r.unit?.id;
  if (!roomId || !r.arrival || !r.departure) continue;
  if (!roomMap[roomId]) {
    roomMap[roomId] = { roomId, roomName: r.unit?.name, property: r.property?.name, reservations: [] };
  }
  roomMap[roomId].reservations.push({ arrival: toDateOnly(r.arrival), departure: toDateOnly(r.departure), status: r.status, reservationId: r.id, bookingId: r.booking?.id });
}

const roomTimelines = Object.values(roomMap).map(room => {
  const sorted = room.reservations.sort((a, b) => a.arrival.localeCompare(b.arrival));
  const occupiedToday = sorted.some(r => r.arrival <= todayStr && r.departure > todayStr);
  const checkoutToday = sorted.some(r => r.departure === todayStr);
  const checkinToday  = sorted.some(r => r.arrival === todayStr);
  const pastDepartures = sorted.filter(r => r.status === 'CheckedOut' && r.departure <= todayStr).map(r => r.departure).sort();
  const lastCheckedOutDeparture = pastDepartures.length ? pastDepartures[pastDepartures.length - 1] : null;
  const daysVacantSinceCheckout = (!occupiedToday && lastCheckedOutDeparture) ? daysBetween(lastCheckedOutDeparture, todayStr) : null;
  const legionellaRisk = daysVacantSinceCheckout !== null && daysVacantSinceCheckout >= LEGIONELLA_MAX_DAYS;
  const pastReservations = sorted.filter(r => r.departure <= todayStr);
  const lastReservation = pastReservations[pastReservations.length - 1] ?? null;
  const todayReservation = sorted.find(r => r.arrival <= todayStr && r.departure >= todayStr) ?? null;
  const availableWindows = [];
  const futureReservations = sorted.filter(r => r.departure > todayStr);
  let cursor = todayStr;
  for (const res of futureReservations) {
    if (cursor < res.arrival) {
      const from = cursor < todayStr ? todayStr : cursor;
      const to   = res.arrival;
      if (from < to) availableWindows.push({ from, to, daysAvailable: daysBetween(from, to), openEnded: false });
    }
    if (res.departure > cursor) cursor = res.departure;
  }
  if (cursor < windowEnd) {
    const from = cursor < todayStr ? todayStr : cursor;
    availableWindows.push({ from, to: windowEnd, daysAvailable: daysBetween(from, windowEnd), openEnded: true });
  }
  let statusToday = 'available';
  if (occupiedToday) statusToday = 'occupied';
  else if (checkoutToday) statusToday = 'checkout_today';
  return { roomId: room.roomId, roomName: room.roomName, property: room.property, statusToday, checkinToday, checkoutToday, lastCheckedOutDeparture, daysVacantSinceCheckout, legionellaRisk, legionellaThresholdDays: LEGIONELLA_MAX_DAYS, availableWindows, reservations: sorted, lastReservation, todayReservation };
});

const sortedTimelines = roomTimelines.sort((a, b) => {
  const aName = a.roomName ?? '', bName = b.roomName ?? '';
  const aNum = parseInt(aName, 10), bNum = parseInt(bName, 10);
  if (!isNaN(aNum) && !isNaN(bNum)) return aNum - bNum;
  return aName.localeCompare(bName);
});

return [{ json: { RoomRack: sortedTimelines } }];

const bucketItems = $('Blocked_AvailToday_Preassigned').all();
const units = $input.first().json.units || [];
const blockedRoomIds = new Set();
const availableTodayIds = new Set();
for (const item of bucketItems) {
  const bucket = item.json;
  if (bucket.bucket === 'blocked_rooms') for (const room of bucket.rooms || []) blockedRoomIds.add(room.roomId);
  if (bucket.bucket === 'available_today') for (const room of bucket.rooms || []) availableTodayIds.add(room.roomId);
}
function mapUnit(unit) { return { roomId: unit.id, roomName: unit.name, propertyId: unit.property?.id, unitGroupId: unit.unitGroup?.id, maxPersons: unit.maxPersons, condition: unit.status?.condition || 'Unknown', isOccupied: unit.status?.isOccupied || false, attributes: unit.attributes?.map(a => a.name) || [] }; }
const availableClean = [], availableInspect = [], availableDirty = [], availableToday = [];
for (const unit of units) {
  const roomId = unit.id;
  const hasMaintenance = !!unit.status?.maintenance;
  if (hasMaintenance) continue;
  const room = mapUnit(unit);
  if (!blockedRoomIds.has(roomId)) {
    switch (room.condition) {
      case 'Clean': availableClean.push(room); break;
      case 'Inspect': availableInspect.push(room); break;
      default: availableDirty.push(room);
    }
  }
  if (availableTodayIds.has(roomId)) availableToday.push(room);
}
return [{ json: { availableRooms: { available_clean: availableClean, available_inspect: availableInspect, available_dirty: availableDirty, available_today: availableToday } } }];

const inventory = $('AllRooms').first().json.units;
const uniqueAttributesMap = new Map();
inventory.forEach(unit => {
    if (unit.attributes && Array.isArray(unit.attributes)) {
        unit.attributes.forEach(attr => { if (!uniqueAttributesMap.has(attr.id)) uniqueAttributesMap.set(attr.id, attr); });
    }
});
const unitAttributes = Array.from(uniqueAttributesMap.values());
return [{ json: { unitAttributes, count: unitAttributes.length } }];

const items = $input.all();
const maintenances = [];
for (const item of items) if (Array.isArray(item.json.maintenances)) maintenances.push(...item.json.maintenances);
const result = maintenances.map(m => ({ roomId: m.unit?.id ?? null, roomName: m.unit?.name ?? null, from: m.from ?? null, to: m.to ?? null, type: m.type ?? null, description: m.description ?? null }));
return [{ json: { MaintenanceSlots: result } }];

const firstItem = items[0];
const allReservations = firstItem.json.reservations || firstItem.json[0]?.reservations || [];
const confirmedReservations = allReservations.filter(r => r.status === 'Confirmed');
const mappedReservations = confirmedReservations.map(r => ({ bookingId: r.bookingId, reservationId: r.id, arrival: r.arrival, departure: r.departure, roomType: r.unitGroup?.id || null, guestComment: r.guestComment || null, comment: r.comment || null }));
return [{ json: { reservations: mappedReservations } }];

// =====================================================================
// Simulated Annealing — Room Allocation Optimizer (v2)
//
// Changes vs. v1:
//   • Reads BuildConfig once → all weights/caps/flags/legionella threshold
//     come from there. No more prep1/prep2/prep3.
//   • Every scored feature is gated on its enabled flag; disabled features
//     contribute zero (and their math is skipped entirely).
//   • Priority multipliers were already baked into the weights by
//     BuildConfig, so this file just consumes them.
//   • ASB matching now resolves room-number references ("ASB von 216")
//     in addition to reservation/booking IDs, and records unmet ASBs
//     in diagnostics for the report layer.
//   • Legionella threshold is configurable (it actually comes pre-baked
//     in the room rack — this node just respects the flag).
// =====================================================================

const SA = {
  iterations:       20000,
  startTemp:        200.0,
  endTemp:          0.3,
  traceEvery:       300,
  traceOnAccept:    false,
  traceMaxEntries:  500,
};
const ALLOW_TOMORROW = true;

// ---------- load config ----------
const cfg = $('BuildConfig').first().json;
if (!cfg) throw new Error("Missing BuildConfig output");

const W            = cfg.weights ?? {};
const FEAT         = cfg.features ?? {};
const ranks        = cfg.roomTypeRanks ?? [];
const protectedSet = new Set(cfg.protectedSuiteRanks ?? []);

const ALLOW_OPTIONAL_UPGRADES = cfg.optionalUpgradesAllowed !== false;
const UNASSIGNED_PENALTY      = W.unassignedPenalty ?? -250000;
const PENALTY_INCOMPATIBLE    = W.hardConstraintPenalty ?? -1000000;

// Feature switches
const F = {
  critical:       FEAT.critical?.enabled       !== false,
  preference:     FEAT.preference?.enabled     !== false,
  adjacency:      FEAT.adjacency?.enabled      !== false,
  groupProximity: FEAT.groupProximity?.enabled !== false,
  floorPref:      FEAT.floorPreference?.enabled !== false,
  upgrade:        FEAT.upgrade?.enabled        !== false,
  eci:            FEAT.eci?.enabled            !== false,
  asb:            FEAT.asb?.enabled            !== false,
  legionella:     FEAT.legionella?.enabled     !== false,
};

// ---------- inputs ----------
const reservationsRaw   = $('ArrivalsToday').first()?.json?.reservations ?? [];
const availableRooms    = $('AvailableRoomsByScoring').first()?.json?.availableRooms ?? {};
const unitAttributesRaw = $('UniqueAttributes').first().json.unitAttributes ?? [];
const roomRack          = $('Blocked_AvailToday_Preassigned').first()?.json?.RoomRack ?? [];
const maintenanceSlots  = $('Maintenance_Slots').first()?.json?.MaintenanceSlots ?? [];

// AI Agent output → merge per reservation
const agentOutputRaw    = $('AI Agent').first()?.json?.output ?? [];
const agentMap          = new Map(agentOutputRaw.map(a => [a.reservationId, a]));

// ---------- helpers ----------
const toDateOnly = (iso) => iso ? iso.split('T')[0] : null;

// "Target date" = today if assigning for today, today+1 if assigning for tomorrow.
// Every date-relative check (legionella vacancy, rack windows, ECI, feasibility)
// uses this as the anchor so the workflow can be scheduled the evening before.
const ASSIGN_DAY_OFFSET = Number(cfg.assignDayOffset ?? 0);
function addDaysISO(date, n) {
  const d = new Date(date);
  d.setUTCDate(d.getUTCDate() + n);
  return d.toISOString();
}
const todayStr = toDateOnly(addDaysISO(new Date(), ASSIGN_DAY_OFFSET));

function floorOf(roomName) {
  const digits = String(roomName ?? "").replace(/\D/g, "");
  if (!digits || digits.length < 2) return null;
  return Math.floor(parseInt(digits, 10) / 100);
}

// ---------- maintenance & rack lookups ----------
const maintenanceBlockedRooms = new Set();
for (const m of maintenanceSlots) {
  if (!m.roomId || !m.from || !m.to) continue;
  const mFrom = toDateOnly(m.from), mTo = toDateOnly(m.to);
  if (mFrom <= todayStr && mTo >= todayStr) maintenanceBlockedRooms.add(m.roomId);
}

const roomRackMap = new Map();
const roomRackByName = new Map();           // roomName → rack entry (for ASB room-number lookup)
for (const entry of roomRack) {
  roomRackMap.set(entry.roomId, entry);
  if (entry.roomName) {
    const digits = String(entry.roomName).replace(/\D/g, "");
    if (digits) roomRackByName.set(digits, entry);
    roomRackByName.set(String(entry.roomName).toLowerCase(), entry);
  }
}

function isRoomBlockedByRack(roomId, arrivalDate, departureDate) {
  const entry = roomRackMap.get(roomId);
  if (!entry) return false;
  const hasWindow = (entry.availableWindows ?? []).some(w => {
    const winFrom = w.from;
    const winTo   = w.openEnded ? '9999-12-31' : w.to;
    return winFrom <= arrivalDate && winTo >= departureDate;
  });
  if (hasWindow) return false;
  if (entry.openEndedAfter && entry.openEndedAfter <= arrivalDate) return false;
  return true;
}

// ---------- attribute names ----------
const attrIdToName = new Map(
  unitAttributesRaw.filter(a => a?.id && a?.name)
    .map(a => [String(a.id), String(a.name).toLowerCase().trim()])
);

// ---------- ranks ----------
const rankMap = new Map(ranks.filter(r => r?.id).map(r => [r.id, r.rank]));
const rankOf  = id => rankMap.has(id) ? rankMap.get(id) : null;

// ---------- flatten rooms ----------
const CATEGORIES = ["available_clean","available_inspect","available_dirty","available_tomorrow"];
function flattenRooms(obj) {
  const byId = new Map(), out = [];
  for (const cat of CATEGORIES) {
    for (const r of (Array.isArray(obj?.[cat]) ? obj[cat] : [])) {
      if (!r?.roomId || byId.has(r.roomId)) continue;
      const room = { ...r, __category: cat };
      out.push(room); byId.set(r.roomId, room);
    }
  }
  return { rooms: out, roomById: byId };
}
const { rooms: allRooms, roomById } = flattenRooms(availableRooms);
const rooms = allRooms.filter(r => !maintenanceBlockedRooms.has(r.roomId));

// ---------- neighbor map (adjacency by same floor + ±1 unit number) ----------
const allKnownRoomsForAdjacency = [...allRooms];
const allKnownRoomIds = new Set(allRooms.map(r => r.roomId));
for (const entry of roomRack) {
  if (!entry.roomId || allKnownRoomIds.has(entry.roomId)) continue;
  allKnownRoomsForAdjacency.push({ roomId: entry.roomId, roomName: entry.roomName ?? entry.roomId });
}
function defaultAreAdjacent(a, b) {
  if (!a || !b) return false;
  const na = String(a.roomName ?? "").replace(/\D/g, "");
  const nb = String(b.roomName ?? "").replace(/\D/g, "");
  if (!na || !nb || na.length !== nb.length) return false;
  const ia = parseInt(na, 10), ib = parseInt(nb, 10);
  if (isNaN(ia) || isNaN(ib)) return false;
  return Math.floor(ia/100) === Math.floor(ib/100) && Math.abs(ia-ib) === 1;
}
const neighborMap = new Map();
for (const r of allKnownRoomsForAdjacency) neighborMap.set(r.roomId, new Set());
for (let i = 0; i < allKnownRoomsForAdjacency.length; i++)
  for (let j = i+1; j < allKnownRoomsForAdjacency.length; j++)
    if (defaultAreAdjacent(allKnownRoomsForAdjacency[i], allKnownRoomsForAdjacency[j])) {
      neighborMap.get(allKnownRoomsForAdjacency[i].roomId).add(allKnownRoomsForAdjacency[j].roomId);
      neighborMap.get(allKnownRoomsForAdjacency[j].roomId).add(allKnownRoomsForAdjacency[i].roomId);
    }

function distanceSteps(a, b, maxD = 4) {
  if (!a || !b) return maxD;
  if (a === b) return 0;
  const q = [a], seen = new Set([a]); let d = 0;
  while (q.length && d < maxD) {
    const n = q.length; d++;
    for (let i = 0; i < n; i++) {
      const cur = q.shift();
      for (const nb of neighborMap.get(cur) || []) {
        if (nb === b) return d;
        if (!seen.has(nb)) { seen.add(nb); q.push(nb); }
      }
    }
  }
  return maxD;
}
function distKey(d, gradient) {
  const dk = String(d);
  if (dk in gradient) return dk;
  const numKeys = Object.keys(gradient).filter(k => /^\d+$/.test(k)).map(Number).sort((a,b) => a-b);
  const plusKey = Object.keys(gradient).find(k => k.endsWith("+"));
  for (let i = numKeys.length-1; i >= 0; i--)
    if (d >= numKeys[i]) { const c = String(numKeys[i]); if (c in gradient) return c; }
  return plusKey ?? dk;
}

// ---------- inventory & demand ----------
const inventoryByType = new Map();
for (const r of rooms) {
  if (!inventoryByType.has(r.unitGroupId)) inventoryByType.set(r.unitGroupId, { total: 0, free: 0 });
  const e = inventoryByType.get(r.unitGroupId);
  e.total++;
  if (!r.isOccupied) e.free++;
}
const demandByType = new Map();
for (const r of reservationsRaw)
  demandByType.set(r.roomType, (demandByType.get(r.roomType) ?? 0) + 1);

function classifyUpgrade(toType) {
  const supply = inventoryByType.get(toType)?.free ?? 0;
  const demand = demandByType.get(toType) ?? 0;
  const surplus = supply - demand;
  if (surplus > 3) return "good";
  if (surplus >= 0) return "neutral";
  return "bad";
}

// ---------- merge AI output into reservations ----------
const reservationsWithAgent = reservationsRaw.map(r => {
  const agent = agentMap.get(r.reservationId) ?? {};
  return {
    ...r,
    matchedRequests:         agent.matchedRequests         ?? [],
    inferredMatchedRequests: agent.inferredMatchedRequests ?? [],
    allowedActions:          agent.allowedActions          ?? [],
  };
});
const resIdSet = new Set(reservationsWithAgent.map(r => r.reservationId));

function sanitizeAllowedActions(res) {
  const out = [], seen = new Set();
  for (const a of res.allowedActions ?? []) {
    const { action, mode } = a ?? {};
    if (!action || (mode !== "FORCED" && mode !== "OPTIONAL")) continue;
    const mAdj = action.match(/^Adjacency:\s*([A-Za-z0-9_-]+)$/);
    if (mAdj && (!resIdSet.has(mAdj[1]) || mAdj[1] === res.reservationId)) continue;
    const key = `${action}|${mode}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({ action, mode });
  }
  return out;
}
const reservations     = reservationsWithAgent.map(r => ({ ...r, allowedActions: sanitizeAllowedActions(r) }));
const reservationsById = new Map(reservations.map(r => [r.reservationId, r]));

// ---------- action extractors ----------
const normaliseAttr = s => String(s).toLowerCase().trim();
function resolveMatchedAttr(key, value) {
  if (attrIdToName.has(key)) return attrIdToName.get(key);
  return normaliseAttr(String(value));
}
function requestedAttributes(res) {
  const critical = [], preference = [];
  for (const obj of res.matchedRequests ?? []) {
    const k = obj && Object.keys(obj)[0]; if (!k) continue;
    const resolved = resolveMatchedAttr(k, obj[k]);
    if (resolved) critical.push(resolved);
  }
  for (const obj of res.inferredMatchedRequests ?? []) {
    const k = obj && Object.keys(obj)[0];
    const v = k ? obj[k] : null;
    if (v?.attributeType) preference.push({
      name:       normaliseAttr(String(v.attributeType)),
      inferredBy: String(v.inferredBy ?? "")
    });
  }
  return { critical, preference };
}
function extractUpgrade(res) {
  let best = null;
  for (const a of res.allowedActions ?? []) {
    const m = a.action.match(/^Upgrade\s+([1-9])$/);
    if (!m) continue;
    const lvl = Number(m[1]);
    if (!best || lvl > best.level) best = { level: lvl, mode: a.mode };
  }
  return best;
}
function extractAdjPairs(res) {
  const out = [];
  for (const a of res.allowedActions ?? []) {
    const m = a.action.match(/^Adjacency:\s*([A-Za-z0-9_-]+)$/);
    if (m) out.push({ otherReservationId: m[1], mode: a.mode });
  }
  return out;
}
const hasEarlyCheckIn = res => (res.allowedActions ?? []).some(a => a.action === "EarlyCheckIn");
function extractASB(res) {
  for (const a of res.allowedActions ?? []) {
    const m = a.action.match(/^ASB:\s*(.+)$/);
    if (m) return m[1].trim();
  }
  return null;
}
function extractFloorPreference(res) {
  for (const a of res.allowedActions ?? []) {
    if (a.action === "FloorPreference: high") return "high";
    if (a.action === "FloorPreference: low")  return "low";
  }
  return null;
}

// ---------- ASB resolver: identifier → roomId ----------
// Handles three input shapes, in order of confidence:
//   1. raw reservation/booking id matched against rack reservation history
//   2. "von 216", "von Zimmer 216", "von Room 216", "216" → room number
//   3. anything else: best-effort substring match
function resolveAsbRoom(identifier) {
  if (!identifier) return null;
  const id = String(identifier).trim();

  // (1) reservation/booking id in rack
  const byResv = roomRack.find(e =>
    (e.reservations ?? []).some(r =>
      r.reservationId === id ||
      r.bookingId === id ||
      String(r.reservationId ?? "").includes(id) ||
      String(r.bookingId ?? "").includes(id)
    )
  );
  if (byResv) return { roomId: byResv.roomId, source: "reservationOrBookingId" };

  // (2) room number — extract trailing digit run after optional preposition
  const numMatch = id.match(/(?:^|[\s:#])(\d{2,5})\s*$/) || id.match(/(\d{2,5})/);
  if (numMatch) {
    const digits = numMatch[1];
    const entry = roomRackByName.get(digits);
    if (entry) return { roomId: entry.roomId, source: "roomNumber" };
  }

  // (3) full string match against room name
  const byName = roomRackByName.get(id.toLowerCase());
  if (byName) return { roomId: byName.roomId, source: "roomName" };

  return null;
}

// ---------- floor range for normalisation ----------
const allFloors = [...new Set(allRooms.map(r => floorOf(r.roomName)).filter(f => f !== null))]
  .sort((a,b) => a-b);
const MIN_FLOOR = allFloors[0] ?? 1;
const MAX_FLOOR = allFloors[allFloors.length-1] ?? 1;

// ---------- feasibility ----------
function isFeasibleBase(res, room) {
  if (!room) return false;
  if (maintenanceBlockedRooms.has(room.roomId)) return false;
  const arrivalDate   = toDateOnly(res.arrival)   ?? todayStr;
  const departureDate = toDateOnly(res.departure) ?? todayStr;
  if (isRoomBlockedByRack(room.roomId, arrivalDate, departureDate)) return false;
  const bRank = rankOf(res.roomType), rRank = rankOf(room.unitGroupId);
  if (bRank === null || rRank === null) return res.roomType === room.unitGroupId;
  if (rRank < bRank) return false;
  if (rRank > bRank) {
    const up = extractUpgrade(res);
    if (protectedSet.has(rRank) && (!up || up.mode !== "FORCED")) return false;
    if (!ALLOW_OPTIONAL_UPGRADES && (!up || up.mode !== "FORCED")) return false;
  }
  return true;
}
function isFeasible(res, room) {
  if (!isFeasibleBase(res, room)) return false;
  if (!ALLOW_TOMORROW && room.__category === "available_tomorrow") return false;
  if (F.eci && hasEarlyCheckIn(res)) {
    if (room.__category === "available_dirty" || room.__category === "available_tomorrow") return false;
    if (room.isOccupied) return false;
  }
  return true;
}
function isFeasibleECIFallback(res, room) {
  if (!ALLOW_TOMORROW && room.__category === "available_tomorrow") return false;
  return isFeasibleBase(res, room);
}

// ---------- per-room bonus (state + ECI + legionella) ----------
function getAvailabilityBonus(room, res) {
  let bonus = room.isOccupied
    ? (W.roomState?.occupied ?? -350)
    : (W.roomState?.[room.__category?.replace("available_", "")] ?? 0);
  if (F.eci && res && hasEarlyCheckIn(res)) {
    if (room.__category === "available_dirty" || room.isOccupied) {
      bonus -= (W.eciDirtyExtraPenalty ?? 400);
    }
  }
  if (F.legionella) {
    const rackEntry = roomRackMap.get(room.roomId);
    if (rackEntry?.legionellaRisk === true) bonus += (W.legionellaAssignmentBonus ?? 800);
  }
  return bonus;
}

function getFloorBonus(res, room) {
  if (!F.floorPref) return 0;
  const pref = extractFloorPreference(res);
  if (!pref) return 0;
  const floor = floorOf(room.roomName);
  if (floor === null) return 0;
  if (MIN_FLOOR === MAX_FLOOR) return 0;
  const step = W.floorPrefBonusPerStep ?? 15;
  if (pref === "high") return (floor - MIN_FLOOR) * step;
  return (MAX_FLOOR - floor) * step;
}

function buildUpgradeRationale(bookedType, assignedType, bRank, rRank, explicitUpgrade, baseQuality, effectiveQuality) {
  const inv = inventoryByType.get(assignedType) ?? { total: 0, free: 0 };
  const demand = demandByType.get(assignedType) ?? 0;
  const surplus = inv.free - demand;
  const tierJump = rRank - bRank;
  const inventoryLine = surplus > 3
    ? `${assignedType}: ${inv.total} rooms available, ${inv.free} unoccupied, ${demand} booked at this type (surplus ${surplus}) — spare capacity exists.`
    : surplus >= 0
    ? `${assignedType}: ${inv.total} rooms available, ${inv.free} unoccupied, ${demand} booked at this type (surplus ${surplus}) — supply and demand balanced.`
    : `${assignedType}: ${inv.total} rooms available, ${inv.free} unoccupied, ${demand} booked at this type (surplus ${surplus}) — insufficient capacity.`;
  const actionLine = explicitUpgrade
    ? `Upgrade ${explicitUpgrade.level} [${explicitUpgrade.mode}] applied.`
    : ALLOW_OPTIONAL_UPGRADES ? "Implicit upgrade — no explicit action."
                              : "FORCED action — implicit upgrades disabled globally.";
  const qualityLine = `Base quality: ${baseQuality}.${baseQuality !== effectiveQuality ? ` Boosted to "${effectiveQuality}" by explicit action.` : ""}`;
  return {
    summary: `Booked ${bookedType} (rank ${bRank}) → assigned ${assignedType} (rank ${rRank}, ${tierJump} tier${tierJump !== 1 ? "s" : ""} up). Quality "${effectiveQuality}".`,
    bookedType, assignedType, tierJump,
    inventory: { total: inv.total, free: inv.free, demand, surplus },
    baseQuality, effectiveQuality,
    qualityBoostedByAction: baseQuality !== effectiveQuality,
    explicitAction: explicitUpgrade ? { level: explicitUpgrade.level, mode: explicitUpgrade.mode } : null,
    explanation: [inventoryLine, actionLine, qualityLine].join(" "),
  };
}

// ---------- validation ----------
function isValidAssignment(assignMap) {
  const used = new Set();
  for (const roomId of assignMap.values()) {
    if (used.has(roomId)) return false;
    used.add(roomId);
  }
  return true;
}

// ---------- per-reservation scoring ----------
function scoreReservationWithBreakdown(res, room, assignmentMap) {
  if (!room) return { score: UNASSIGNED_PENALTY, breakdown: { feasibility: "UNASSIGNED", total: UNASSIGNED_PENALTY } };
  if (!isFeasible(res, room)) return { score: PENALTY_INCOMPATIBLE, breakdown: { feasibility: "INCOMPATIBLE", total: PENALTY_INCOMPATIBLE } };

  let score = 0;
  const bd = {
    feasibility:     "OK",
    availability:    0,
    floorPreference: 0,
    critical:   { requested: [], satisfied: [], unsatisfied: [], score: 0 },
    preference: { requested: [], satisfied: [], unsatisfied: [], score: 0 },
    upgrade:    { applied: false, quality: null, hasExplicitAction: false, score: 0, rationale: null },
    adjacency:  { forced: { score: 0, pairs: [] }, optional: { score: 0, pairs: [] } },
    flags:      { earlyCheckIn: hasEarlyCheckIn(res), asbIdentifier: extractASB(res), floorPreference: extractFloorPreference(res) },
    total:      0,
  };

  bd.availability    = getAvailabilityBonus(room, res); score += bd.availability;
  bd.floorPreference = getFloorBonus(res, room);        score += bd.floorPreference;

  const attrsNorm = new Set((room.attributes ?? []).map(normaliseAttr));
  const { critical, preference } = requestedAttributes(res);
  bd.critical.requested   = [...critical];
  bd.preference.requested = preference.map(x => ({ attributeType: x.name, inferredBy: x.inferredBy }));

  if (F.critical) {
    let critScore = 0;
    for (const a of critical) {
      if (attrsNorm.has(a)) { bd.critical.satisfied.push(a);   critScore += W.critSat ?? 0; }
      else                  { bd.critical.unsatisfied.push(a); critScore += W.critUnsat ?? 0; }
    }
    critScore = Math.max(critScore, W.critCap ?? -1200);
    bd.critical.score = critScore;
    score += critScore;
  }

  if (F.preference) {
    let prefScore = 0;
    for (const p of preference) {
      if (attrsNorm.has(p.name)) { bd.preference.satisfied.push(p.name);   prefScore += W.prefSat ?? 0; }
      else                       { bd.preference.unsatisfied.push(p.name); prefScore += W.prefUnsat ?? 0; }
    }
    prefScore = Math.max(prefScore, W.prefCap ?? -600);
    bd.preference.score = prefScore;
    score += prefScore;
  }

  if (F.upgrade) {
    const bRank = rankOf(res.roomType), rRank = rankOf(room.unitGroupId);
    if (bRank !== null && rRank !== null && rRank > bRank) {
      const baseQuality     = classifyUpgrade(room.unitGroupId);
      const explicitUpgrade = extractUpgrade(res);
      const hasAction       = Boolean(explicitUpgrade);
      let effectiveQuality  = baseQuality;
      if (hasAction) {
        if (baseQuality === "bad")     effectiveQuality = "neutral";
        else if (baseQuality === "neutral") effectiveQuality = "good";
      }
      const raw = effectiveQuality === "good" ? (W.upgradeGood ?? 0)
                : effectiveQuality === "neutral" ? (W.upgradeNeutral ?? 0)
                : (W.upgradeBad ?? 0);
      const cap = W.upgradeCap ?? 200;
      const upScore = Math.max(Math.min(raw, cap), -cap);
      bd.upgrade = {
        applied: true, quality: effectiveQuality, baseQuality,
        hasExplicitAction: hasAction, mode: explicitUpgrade?.mode ?? null,
        score: upScore,
        rationale: buildUpgradeRationale(res.roomType, room.unitGroupId, bRank, rRank, explicitUpgrade, baseQuality, effectiveQuality),
      };
      score += upScore;
    }
  }

  if (F.adjacency) {
    const pairs = extractAdjPairs(res);
    let forcedTotal = 0, optTotal = 0;
    for (const p of pairs) {
      const otherRoomId = assignmentMap.get(p.otherReservationId) ?? null;
      const d = otherRoomId ? distanceSteps(room.roomId, otherRoomId) : 4;
      const gradient = p.mode === "FORCED" ? W.adjForcedByDist : W.adjOptByDist;
      const adjScore = gradient?.[distKey(d, gradient ?? {})] ?? 0;
      const entry = { otherReservationId: p.otherReservationId, otherRoomId, distance: d, score: adjScore };
      if (p.mode === "FORCED") { bd.adjacency.forced.pairs.push(entry);   forcedTotal += adjScore; }
      else                     { bd.adjacency.optional.pairs.push(entry); optTotal    += adjScore; }
    }
    const fCap = W.adjForcedCap ?? 1600, oCap = W.adjOptCap ?? 600;
    forcedTotal = Math.max(Math.min(forcedTotal, fCap), -fCap);
    optTotal    = Math.max(Math.min(optTotal,    oCap), -oCap);
    bd.adjacency.forced.score   = forcedTotal;
    bd.adjacency.optional.score = optTotal;
    score += forcedTotal + optTotal;
  }

  bd.total = score;
  return { score, breakdown: bd };
}

function scoreGlobalWithBreakdown(assignmentMap) {
  let score = 0;
  const bd = { allForcedAdjBonusApplied: false, allForcedAdjBonus: 0, groupFullyClusteredBonus: 0, bookingGroupProximity: 0, total: 0 };

  if (F.adjacency) {
    let forcedTotal = 0, forcedSat = 0;
    for (const res of reservations) {
      const myRoomId = assignmentMap.get(res.reservationId); if (!myRoomId) continue;
      for (const p of extractAdjPairs(res)) {
        if (p.mode !== "FORCED") continue;
        forcedTotal++;
        const otherRoomId = assignmentMap.get(p.otherReservationId);
        if (otherRoomId && distanceSteps(myRoomId, otherRoomId) === 1) forcedSat++;
      }
    }
    if (forcedTotal > 0 && forcedSat === forcedTotal) {
      bd.allForcedAdjBonusApplied = true;
      bd.allForcedAdjBonus = W.allForcedAdjBonus ?? 0;
      score += bd.allForcedAdjBonus;
    }
  }

  if (F.groupProximity) {
    const byBooking = new Map();
    for (const r of reservations) {
      if (!byBooking.has(r.bookingId)) byBooking.set(r.bookingId, []);
      byBooking.get(r.bookingId).push(r.reservationId);
    }
    let prox = 0, clusterBonus = 0;
    for (const [, ids] of byBooking) {
      if (ids.length < 2) continue;
      const roomIds = ids.map(id => assignmentMap.get(id)).filter(Boolean);
      if (roomIds.length < ids.length) continue;
      let maxDist = 0;
      for (let i = 0; i < roomIds.length; i++) for (let j = i+1; j < roomIds.length; j++) {
        const d = distanceSteps(roomIds[i], roomIds[j]);
        prox += W.bookProxByDist?.[distKey(d, W.bookProxByDist ?? {})] ?? 0;
        if (d > maxDist) maxDist = d;
      }
      if (maxDist <= 2) clusterBonus += (W.groupClusterBonus ?? 0);
    }
    prox = Math.min(prox, W.bookProxCapGlobal ?? 1600);
    bd.bookingGroupProximity = prox;
    bd.groupFullyClusteredBonus = clusterBonus;
    score += prox + clusterBonus;
  }

  bd.total = score;
  return { score, breakdown: bd };
}

// ---------- PRE-ASSIGNMENT STEP 1: LEGIONELLA ----------
const preAssignedReservations = new Set();
const preAssignedRooms        = new Set();
const preAssignments          = new Map();
const unmetAsbs               = [];   // [{reservationId, identifier, reason}]

if (F.legionella) {
  const legionellaRooms = roomRack.filter(e => e.legionellaRisk === true);
  for (const legRoom of legionellaRooms) {
    const room = roomById.get(legRoom.roomId);
    if (!room || maintenanceBlockedRooms.has(room.roomId)) continue;
    const candidate = reservations.find(res =>
      !preAssignedReservations.has(res.reservationId) &&
      res.roomType === room.unitGroupId &&
      isFeasibleBase(res, room)
    );
    if (candidate) {
      preAssignments.set(candidate.reservationId, room.roomId);
      preAssignedReservations.add(candidate.reservationId);
      preAssignedRooms.add(room.roomId);
    }
  }
}

// ---------- PRE-ASSIGNMENT STEP 2: ASB ----------
if (F.asb) {
  for (const res of reservations) {
    if (preAssignedReservations.has(res.reservationId)) continue;
    const asbId = extractASB(res);
    if (!asbId) continue;

    const resolved = resolveAsbRoom(asbId);
    if (!resolved) {
      unmetAsbs.push({ reservationId: res.reservationId, identifier: asbId, reason: "Identifier did not match any room (number / reservation / booking)." });
      continue;
    }
    const room = roomById.get(resolved.roomId);
    if (!room) {
      unmetAsbs.push({ reservationId: res.reservationId, identifier: asbId, reason: `Room ${resolved.roomId} not in today's available pool.` });
      continue;
    }
    if (preAssignedRooms.has(room.roomId)) {
      unmetAsbs.push({ reservationId: res.reservationId, identifier: asbId, reason: `Room ${room.roomName} already locked by another pre-assignment (legionella or earlier ASB).` });
      continue;
    }
    if (maintenanceBlockedRooms.has(room.roomId)) {
      unmetAsbs.push({ reservationId: res.reservationId, identifier: asbId, reason: `Room ${room.roomName} blocked for maintenance.` });
      continue;
    }
    if (!isFeasibleBase(res, room)) {
      unmetAsbs.push({ reservationId: res.reservationId, identifier: asbId, reason: `Room ${room.roomName} not feasible (room type / rank / blocking window).` });
      continue;
    }
    preAssignments.set(res.reservationId, room.roomId);
    preAssignedReservations.add(res.reservationId);
    preAssignedRooms.add(room.roomId);
  }
}

// ---------- SA-scoped reservations & rooms ----------
const saReservations = reservations.filter(r => !preAssignedReservations.has(r.reservationId));
const saRooms        = rooms.filter(r => !preAssignedRooms.has(r.roomId));

// ---------- total score ----------
function totalScore(assignMap) {
  const fullMap = new Map([...preAssignments, ...assignMap]);
  let s = 0;
  for (const res of reservations) {
    const roomId = fullMap.get(res.reservationId);
    const room   = roomId ? roomById.get(roomId) : null;
    s += scoreReservationWithBreakdown(res, room, fullMap).score;
  }
  s += scoreGlobalWithBreakdown(fullMap).score;
  return s;
}

// ---------- greedy init ----------
function greedyInit() {
  const items = saReservations.map(r => {
    const eci      = F.eci && hasEarlyCheckIn(r);
    const feasible = saRooms.filter(rm => isFeasible(r, rm));
    const effectiveFeasible = (eci && feasible.length === 0)
      ? saRooms.filter(rm => isFeasibleECIFallback(r, rm))
      : feasible;
    const { critical, preference } = requestedAttributes(r);
    return { res: r, feasible: effectiveFeasible, eci, priority: critical.length*2 + preference.length };
  }).sort((a, b) => {
    if (a.eci !== b.eci) return a.eci ? -1 : 1;
    return (a.feasible.length - b.feasible.length) || (b.priority - a.priority);
  });

  const assign = new Map(), used = new Set();
  for (const { res, feasible } of items) {
    const candidates = feasible.filter(r => !used.has(r.roomId));
    candidates.sort((a, b) => {
      const bkRank = rankOf(res.roomType) ?? 0;
      const aUpg   = (rankOf(a.unitGroupId) ?? 0) - bkRank;
      const bUpg   = (rankOf(b.unitGroupId) ?? 0) - bkRank;
      if (aUpg !== bUpg) return aUpg - bUpg;
      const aBonus = getAvailabilityBonus(a, res) + getFloorBonus(res, a);
      const bBonus = getAvailabilityBonus(b, res) + getFloorBonus(res, b);
      return bBonus - aBonus;
    });
    const contextMap = new Map([...preAssignments, ...assign]);
    let bestId = null, bestSc = -Infinity;
    for (const room of candidates.slice(0, 30)) {
      const tmp = new Map(contextMap); tmp.set(res.reservationId, room.roomId);
      const sc = scoreReservationWithBreakdown(res, room, tmp).score;
      if (sc > bestSc) { bestSc = sc; bestId = room.roomId; }
    }
    if (bestId) { assign.set(res.reservationId, bestId); used.add(bestId); }
  }
  return assign;
}

// ---------- SA moves ----------
const randInt = n => Math.floor(Math.random()*n);
function proposeMove(resIds) {
  const p = Math.random();
  if (p < 0.55 && resIds.length >= 2) {
    const a = resIds[randInt(resIds.length)];
    let b = resIds[randInt(resIds.length)];
    if (b === a) b = resIds[(resIds.indexOf(a)+1) % resIds.length];
    return { type: "swap", a, b };
  }
  if (p < 0.85) return { type: "reassign", a: resIds[randInt(resIds.length)] };
  if (resIds.length >= 3) {
    const a = resIds[randInt(resIds.length)];
    let b = resIds[randInt(resIds.length)];
    let c = resIds[randInt(resIds.length)];
    if (b === a) b = resIds[(resIds.indexOf(a)+1) % resIds.length];
    if (c === a || c === b) c = resIds[(resIds.indexOf(b)+1) % resIds.length];
    return { type: "cycle3", a, b, c };
  }
  return { type: "reassign", a: resIds[randInt(resIds.length)] };
}
function applyMove(move, current) {
  const next = new Map(current);
  if (move.type === "swap") {
    const aRoom = next.get(move.a), bRoom = next.get(move.b);
    if (!aRoom || !bRoom) return current;
    const ra = reservationsById.get(move.a), rb = reservationsById.get(move.b);
    if (!ra || !rb) return current;
    if (!isFeasible(ra, roomById.get(bRoom)) || !isFeasible(rb, roomById.get(aRoom))) return current;
    next.set(move.a, bRoom); next.set(move.b, aRoom);
    return isValidAssignment(next) ? next : current;
  }
  if (move.type === "cycle3") {
    const aR = next.get(move.a), bR = next.get(move.b), cR = next.get(move.c);
    if (!aR || !bR || !cR) return current;
    const ra = reservationsById.get(move.a), rb = reservationsById.get(move.b), rc = reservationsById.get(move.c);
    if (!ra || !rb || !rc) return current;
    if (!isFeasible(ra, roomById.get(bR)) || !isFeasible(rb, roomById.get(cR)) || !isFeasible(rc, roomById.get(aR))) return current;
    next.set(move.a, bR); next.set(move.b, cR); next.set(move.c, aR);
    return isValidAssignment(next) ? next : current;
  }
  const res = reservationsById.get(move.a);
  if (!res) return current;
  const oldRoom = next.get(move.a) ?? null;
  next.delete(move.a);
  const used = new Set(next.values());
  const { critical, preference } = requestedAttributes(res);
  const bkRank = rankOf(res.roomType) ?? 0;
  const candidates = saRooms
    .filter(r => !used.has(r.roomId) && isFeasible(res, r))
    .sort((r1, r2) => {
      const s1 = new Set((r1.attributes ?? []).map(normaliseAttr));
      const s2 = new Set((r2.attributes ?? []).map(normaliseAttr));
      const m1 = critical.reduce((s,a) => s+(s1.has(a)?2:0), 0)
               + preference.reduce((s,p) => s+(s1.has(p.name)?1:0), 0);
      const m2 = critical.reduce((s,a) => s+(s2.has(a)?2:0), 0)
               + preference.reduce((s,p) => s+(s2.has(p.name)?1:0), 0);
      if (m1 !== m2) return m2 - m1;
      const u1 = (rankOf(r1.unitGroupId) ?? 0) - bkRank;
      const u2 = (rankOf(r2.unitGroupId) ?? 0) - bkRank;
      if (u1 !== u2) return u1 - u2;
      const b1 = getAvailabilityBonus(r1, res) + getFloorBonus(res, r1);
      const b2 = getAvailabilityBonus(r2, res) + getFloorBonus(res, r2);
      return b2 - b1;
    });
  if (candidates.length > 0) {
    next.set(move.a, candidates[randInt(Math.min(5, candidates.length))].roomId);
  } else if (oldRoom) {
    next.set(move.a, oldRoom);
  }
  return isValidAssignment(next) ? next : current;
}

// ---------- SA main ----------
function simulatedAnnealing() {
  const resIds = saReservations.map(r => r.reservationId);
  if (resIds.length === 0) return { best: new Map(), bestScore: 0, trace: [] };
  let current      = greedyInit();
  let currentScore = totalScore(current);
  let best         = new Map(current), bestScore = currentScore;
  const trace      = [{ iter: 0, currentScore, bestScore }];
  for (let t = 1; t <= SA.iterations; t++) {
    const frac = t/SA.iterations;
    const temp = SA.startTemp*Math.pow(SA.endTemp/SA.startTemp, frac);
    const move = proposeMove(resIds);
    const cand = applyMove(move, current);
    const candScore = totalScore(cand);
    const delta     = candScore - currentScore;
    const accept    = delta >= 0 || Math.random() < Math.exp(delta/Math.max(1e-9, temp));
    if (accept) { current = cand; currentScore = candScore; }
    if (candScore > bestScore) { best = new Map(cand); bestScore = candScore; }
    const shouldTrace = (t % SA.traceEvery === 0) || (candScore > bestScore);
    if (shouldTrace && trace.length < SA.traceMaxEntries)
      trace.push({ iter: t, temp: +temp.toFixed(3), currentScore, bestScore, moveType: move.type, accepted: accept });
  }
  return { best, bestScore, trace };
}

// ---------- output builders ----------
function buildReservationReport(res, fullAssignmentMap) {
  const roomId = fullAssignmentMap.get(res.reservationId) ?? null;
  const room   = roomId ? roomById.get(roomId) : null;
  const { score, breakdown } = scoreReservationWithBreakdown(res, room, fullAssignmentMap);
  const asb = extractASB(res);
  return {
    bookingId:      res.bookingId,
    reservationId:  res.reservationId,
    roomTypeBooked: res.roomType,
    guestComment:   res.guestComment,
    comment:        res.comment,
    aiRequests: {
      matchedRequests:         res.matchedRequests ?? [],
      inferredMatchedRequests: res.inferredMatchedRequests ?? [],
      allowedActions:          res.allowedActions ?? [],
    },
    preAssigned: preAssignments.has(res.reservationId)
      ? { reason: asb ? "ASB" : "Legionella", roomId: preAssignments.get(res.reservationId) } : null,
    asbRequested:  asb,
    asbResolved:   asb ? resolveAsbRoom(asb) : null,
    assignment: room ? {
      roomId:      room.roomId,
      roomName:    room.roomName,
      floor:       floorOf(room.roomName),
      unitGroupId: room.unitGroupId,
      category:    room.__category,
      condition:   room.condition,
      isOccupied:  room.isOccupied,
      attributes:  room.attributes ?? [],
      roomRank:    rankOf(room.unitGroupId),
      bookedRank:  rankOf(res.roomType),
      isUpgrade:   (rankOf(room.unitGroupId) ?? -Infinity) > (rankOf(res.roomType) ?? Infinity),
    } : null,
    reservationScore: score,
    breakdown,
  };
}
function buildRoomReport(roomId, fullAssignmentMap) {
  const room = roomById.get(roomId); if (!room) return null;
  return {
    roomId:      room.roomId,
    roomName:    room.roomName,
    floor:       floorOf(room.roomName),
    unitGroupId: room.unitGroupId,
    category:    room.__category,
    condition:   room.condition,
    isOccupied:  room.isOccupied,
    attributes:  room.attributes ?? [],
    assignedTo:  reservations.filter(r => fullAssignmentMap.get(r.reservationId) === roomId).map(r => r.reservationId),
  };
}

// ---------- feasibility diagnostic ----------
const feasibilityReport = reservations.map(res => {
  const arrivalDate   = toDateOnly(res.arrival)   ?? todayStr;
  const departureDate = toDateOnly(res.departure) ?? todayStr;
  const feasible      = saRooms.filter(r => isFeasible(res, r));
  return {
    reservationId:    res.reservationId,
    roomType:         res.roomType,
    arrival:          arrivalDate,
    departure:        departureDate,
    flags: {
      earlyCheckIn:    hasEarlyCheckIn(res),
      asbIdentifier:   extractASB(res),
      floorPreference: extractFloorPreference(res),
      preAssigned:     preAssignments.has(res.reservationId),
    },
    totalFeasible:    feasible.length,
    feasibleRooms:    feasible.map(r => r.roomName),
  };
});

// ---------- run ----------
const { best, bestScore, trace } = simulatedAnnealing();
const finalAssignments = new Map([...preAssignments, ...best]);

const reservationReports = reservations.map(r => buildReservationReport(r, finalAssignments));
const usedRoomIds        = Array.from(new Set(finalAssignments.values()));
const roomReports        = usedRoomIds.map(rid => buildRoomReport(rid, finalAssignments)).filter(Boolean);
const global             = scoreGlobalWithBreakdown(finalAssignments);
const unassigned         = reservationReports.filter(r => !r.assignment).map(r => r.reservationId);

const legionellaUnresolved = F.legionella
  ? roomRack.filter(e => e.legionellaRisk === true && !preAssignedRooms.has(e.roomId) && roomById.has(e.roomId))
            .map(e => ({ roomId: e.roomId, roomName: e.roomName, daysVacant: e.daysVacantSinceCheckout }))
  : [];

return [{
  json: {
    totalScore:           bestScore,
    globalScore:          global.score,
    globalScoreBreakdown: global.breakdown,
    reservations:         reservationReports,
    rooms:                roomReports,
    trace,
    config: {
      features:                FEAT,
      optionalUpgradesAllowed: ALLOW_OPTIONAL_UPGRADES,
      legionellaMaxDays:       cfg.legionellaMaxDays,
      decayExp:                cfg.decayExp,
      propertyId:              cfg.propertyId,
      assignForDay:            cfg.assignForDay,
      targetDate:              todayStr,
    },
    diagnostics: {
      roomsTotal:              saRooms.length,
      roomsExcludedMaint:      allRooms.length - rooms.length,
      maintenanceBlocked:      Array.from(maintenanceBlockedRooms),
      reservationsTotal:       reservations.length,
      preAssignedCount:        preAssignments.size,
      preAssignedReservations: Array.from(preAssignments.entries()).map(([resId, roomId]) => ({
        reservationId: resId,
        roomId,
        reason: extractASB(reservationsById.get(resId)) ? "ASB" : "Legionella",
      })),
      legionellaUnresolved,
      unmetAsbs,
      unassignedCount:         unassigned.length,
      unassigned,
      allowTomorrow:           ALLOW_TOMORROW,
      allowOptionalUpgrades:   ALLOW_OPTIONAL_UPGRADES,
      floorRange:              { min: MIN_FLOOR, max: MAX_FLOOR },
      inventoryByType:         Object.fromEntries(inventoryByType),
      demandByType:            Object.fromEntries(demandByType),
      feasibilityReport,
    },
  },
}];

const data = $input.first().json;
const reservations = data.reservations;
const global = data.globalScoreBreakdown ?? {};
const totalScore = data.totalScore;
const diag = data.diagnostics ?? {};
const cfg  = data.config ?? {};

// Optional-upgrade flag now comes from the config object emitted by SA.
const optionalUpgradeAllowed = cfg.optionalUpgradesAllowed !== false;

// -------------------- helpers --------------------
function esc(str) {
  if (str === null || str === undefined) return "—";
  return String(str)
    .replace(/&/g, "&amp;").replace(/</g, "&lt;")
    .replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}
function na(val) { return (val === null || val === undefined || val === "") ? "—" : val; }
function badge(text, bg, color) {
  color = color || "#ffffff";
  return `<span style="display:inline-block;padding:2px 8px;border-radius:3px;font-size:11px;font-weight:700;letter-spacing:0.5px;background:${bg};color:${color};font-family:Arial,sans-serif;">${esc(text)}</span>`;
}
function statusBadge(feasibility) {
  if (feasibility === "OK")           return badge("ASSIGNED",     "#1a7a4a");
  if (feasibility === "UNASSIGNED")   return badge("UNASSIGNED",   "#c0392b");
  if (feasibility === "INCOMPATIBLE") return badge("INCOMPATIBLE", "#7d3c98");
  return badge(feasibility, "#888888");
}
function scorePill(score) {
  const s = Number(score);
  const bg = s > 0 ? "#e8f5e9" : s < -500 ? "#fdecea" : "#fff8e1";
  const color = s > 0 ? "#1a7a4a" : s < -500 ? "#c0392b" : "#7d6608";
  return `<span style="display:inline-block;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:700;background:${bg};color:${color};font-family:Arial,sans-serif;">${s >= 0 ? "+" : ""}${s}</span>`;
}
function formatMatchedRequests(matched) {
  if (!matched || matched.length === 0) return '<span style="color:#999;font-style:italic;">None</span>';
  return matched.map(obj => {
    const key = Object.keys(obj)[0];
    return `<span style="background:#e3f2fd;color:#1565c0;padding:2px 7px;border-radius:3px;font-size:12px;margin-right:4px;display:inline-block;">${esc(obj[key])}</span>`;
  }).join(" ");
}
function formatInferredRequests(inferred) {
  if (!inferred || inferred.length === 0) return '<span style="color:#999;font-style:italic;">None</span>';
  return inferred.map(obj => {
    const key = Object.keys(obj)[0];
    const val = obj[key];
    return `<span style="background:#f3e5f5;color:#6a1b9a;padding:2px 7px;border-radius:3px;font-size:12px;margin-right:4px;display:inline-block;">${esc(val.attributeType)} <span style="opacity:0.7;font-size:11px;">from "${esc(val.inferredBy)}"</span></span>`;
  }).join(" ");
}
function formatActions(actions) {
  if (!actions || actions.length === 0) return '<span style="color:#999;font-style:italic;">None</span>';
  return actions.map(a => {
    const bg = a.mode === "FORCED" ? "#fdecea" : "#fff8e1";
    const color = a.mode === "FORCED" ? "#c0392b" : "#7d6608";
    return `<span style="background:${bg};color:${color};padding:2px 7px;border-radius:3px;font-size:12px;margin-right:4px;display:inline-block;font-weight:600;">${esc(a.action)} <span style="font-weight:400;font-size:11px;">[${esc(a.mode)}]</span></span>`;
  }).join(" ");
}
function formatAttrList(list, color, bg) {
  if (!list || list.length === 0) return '<span style="color:#999;font-style:italic;">None</span>';
  return list.map(a => {
    const text = typeof a === "object" ? (a.attributeType ?? a.name ?? JSON.stringify(a)) : a;
    return `<span style="background:${bg};color:${color};padding:2px 7px;border-radius:3px;font-size:12px;margin-right:3px;display:inline-block;">${esc(text)}</span>`;
  }).join(" ");
}
function formatRoomAttrs(attrs) {
  if (!attrs || attrs.length === 0) return '<span style="color:#999;font-style:italic;">None</span>';
  return attrs.map(a => `<span style="background:#f5f5f5;color:#333;border:1px solid #ddd;padding:2px 7px;border-radius:3px;font-size:12px;margin-right:3px;display:inline-block;">${esc(a)}</span>`).join(" ");
}
function row(label, value, altBg) {
  const bg = altBg ? "#fafafa" : "#ffffff";
  return `<tr style="background:${bg};">
    <td style="padding:8px 14px;width:180px;color:#666;font-size:13px;font-family:Arial,sans-serif;vertical-align:top;white-space:nowrap;border-bottom:1px solid #f0f0f0;">${label}</td>
    <td style="padding:8px 14px;font-size:13px;font-family:Arial,sans-serif;color:#222;vertical-align:top;border-bottom:1px solid #f0f0f0;">${value}</td>
  </tr>`;
}
function sectionHeader(title, icon) {
  return `<tr><td colspan="2" style="padding:10px 14px 6px 14px;background:#f7f8fa;border-top:2px solid #e8eaed;border-bottom:1px solid #e8eaed;">
    <span style="font-size:11px;font-weight:700;letter-spacing:1px;color:#555;font-family:Arial,sans-serif;text-transform:uppercase;">${icon}&nbsp;&nbsp;${title}</span>
  </td></tr>`;
}
function adjacencyRows(pairs, label) {
  if (!pairs || pairs.length === 0) return "";
  const rows = pairs.map(p => {
    const d = p.distance;
    const status = d <= 1 ? "✅ Adjacent" : d <= 2 ? "🟡 Close" : "❌ Far";
    const distLabel = (d === null || d === undefined) ? "other unassigned" : `${d} step${d !== 1 ? "s" : ""}`;
    return `<tr>
      <td style="padding:4px 8px;font-size:12px;border:1px solid #e0e0e0;">${esc(p.otherReservationId)}</td>
      <td style="padding:4px 8px;font-size:12px;border:1px solid #e0e0e0;">${esc(p.otherRoomId ?? "—")}</td>
      <td style="padding:4px 8px;font-size:12px;border:1px solid #e0e0e0;text-align:center;">${distLabel}</td>
      <td style="padding:4px 8px;font-size:12px;border:1px solid #e0e0e0;">${status}</td>
      <td style="padding:4px 8px;font-size:12px;border:1px solid #e0e0e0;text-align:right;">${scorePill(p.score)}</td>
    </tr>`;
  }).join("");
  return `<tr><td colspan="2" style="padding:6px 14px 10px 14px;">
    <div style="font-size:12px;font-weight:700;color:#555;font-family:Arial,sans-serif;margin-bottom:5px;">${label}</div>
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid #e0e0e0;">
      <tr style="background:#f5f5f5;">
        <th style="padding:5px 8px;font-size:11px;text-align:left;border:1px solid #e0e0e0;">Other Reservation</th>
        <th style="padding:5px 8px;font-size:11px;text-align:left;border:1px solid #e0e0e0;">Other Room</th>
        <th style="padding:5px 8px;font-size:11px;text-align:center;border:1px solid #e0e0e0;">Distance</th>
        <th style="padding:5px 8px;font-size:11px;text-align:left;border:1px solid #e0e0e0;">Status</th>
        <th style="padding:5px 8px;font-size:11px;text-align:right;border:1px solid #e0e0e0;">Score</th>
      </tr>${rows}
    </table>
  </td></tr>`;
}

// -------------------- reservation card --------------------
function reservationCard(res, index) {
  const bd = res.breakdown ?? {};
  const asgn = res.assignment;
  const isOk = bd.feasibility === "OK";
  const headerBg = !asgn ? "#fdecea" : "#f0faf5";
  const headerBorder = !asgn ? "#e74c3c" : "#27ae60";

  let rows = "";
  rows += sectionHeader("Guest Input", "💬");
  rows += row("Comment", esc(na(res.comment)), false);
