  } else {
    rows += row("Room", `<strong>${esc(asgn.roomName)}</strong> <span style="color:#888;font-size:12px;">(${esc(asgn.roomId)})</span>`, false);
    rows += row("Type Assigned", `<strong>${esc(asgn.unitGroupId)}</strong>`, true);
    rows += row("Upgrade", asgn.isUpgrade
      ? `✅ Yes — rank ${esc(asgn.bookedRank)} → rank ${esc(asgn.roomRank)}`
