  }

  if (isOk) {
    rows += sectionHeader("Attribute Matching", "🎯");
    const hasCrit = (bd.critical?.requested?.length ?? 0) > 0;
    const hasPref = (bd.preference?.requested?.length ?? 0) > 0;
    if (hasCrit) {
      rows += row("Critical Requested", formatAttrList(bd.critical.requested, "#1565c0", "#e3f2fd"), false);
      rows += row("Critical Satisfied", formatAttrList(bd.critical.satisfied, "#1a7a4a", "#e8f5e9"), true);
      rows += row("Critical Unsatisfied", bd.critical.unsatisfied.length > 0 ? formatAttrList(bd.critical.unsatisfied, "#c0392b", "#fdecea") : '<span style="color:#1a7a4a;">All satisfied ✅</span>', false);
      rows += row("Critical Score", scorePill(bd.critical.score), true);
    } else {
      rows += row("Critical Requests", '<span style="color:#999;font-style:italic;">None</span>', false);
    }
    if (hasPref) {
      rows += row("Preference Requested", formatAttrList(bd.preference.requested.map(r => r.attributeType ?? r), "#6a1b9a", "#f3e5f5"), !hasCrit);
      rows += row("Preference Satisfied", formatAttrList(bd.preference.satisfied, "#1a7a4a", "#e8f5e9"), hasCrit);
      rows += row("Preference Unsatisfied", bd.preference.unsatisfied.length > 0 ? formatAttrList(bd.preference.unsatisfied, "#c0392b", "#fdecea") : '<span style="color:#1a7a4a;">All satisfied ✅</span>', !hasCrit);
      rows += row("Preference Score", scorePill(bd.preference.score), hasCrit);
    } else {
      rows += row("Preference Requests", '<span style="color:#999;font-style:italic;">None</span>', hasCrit);
    }

    rows += sectionHeader("Upgrade", "⬆️");
    if (bd.upgrade?.applied) {
      rows += row("Applied", "✅ Yes", false);
      rows += row("Explicit Action", bd.upgrade.hasExplicitAction ? `✅ Yes [${esc(bd.upgrade.mode)}]` : "❌ No — implicit upgrade", true);
      rows += row("Base Quality", esc(na(bd.upgrade.baseQuality)), false);
      rows += row("Effective Quality", esc(na(bd.upgrade.quality)), true);
      rows += row("Upgrade Score", scorePill(bd.upgrade.score), false);
      if (bd.upgrade?.rationale) {
        const r = bd.upgrade.rationale;
        const summary = typeof r === "string" ? r : (r.summary ?? r.explanation ?? "");
        rows += row("Rationale", `<em style="color:#555;">${esc(summary)}</em>`, true);
      }
    } else {
      rows += row("Applied", "❌ No — same tier assignment", false);
    }

    const forcedPairs   = bd.adjacency?.forced?.pairs   ?? [];
    const optionalPairs = bd.adjacency?.optional?.pairs ?? [];
    if (forcedPairs.length > 0 || optionalPairs.length > 0) {
      rows += sectionHeader("Adjacency", "🔗");
      if (forcedPairs.length > 0)   rows += adjacencyRows(forcedPairs,   `Forced adjacency — score: ${bd.adjacency.forced.score}`);
      if (optionalPairs.length > 0) rows += adjacencyRows(optionalPairs, `Optional adjacency — score: ${bd.adjacency.optional.score}`);
    }

    rows += sectionHeader("Room State Scoring", "🏷️");
    rows += row("Availability Bonus", scorePill(bd.availability), false);
    if (bd.floorPreference) rows += row("Floor-preference bonus", scorePill(bd.floorPreference), true);
  }

  rows += sectionHeader("Score Summary", "📊");
  rows += `<tr style="background:#f7f8fa;">
    <td style="padding:10px 14px;font-size:13px;color:#333;font-weight:700;vertical-align:middle;">Reservation Total</td>
    <td style="padding:10px 14px;font-size:16px;vertical-align:middle;">${scorePill(res.reservationScore)}</td>
  </tr>`;

  return `<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-bottom:24px;border:1px solid #e0e0e0;border-radius:6px;overflow:hidden;">
    <tr style="background:${headerBg};border-left:4px solid ${headerBorder};">
      <td colspan="2" style="padding:12px 16px;">
        <table width="100%" cellpadding="0" cellspacing="0"><tr>
          <td>
            <span style="font-size:15px;font-weight:700;color:#222;">${esc(res.reservationId)}</span>
            <span style="font-size:12px;color:#666;margin-left:8px;">Booking: ${esc(res.bookingId)}</span>
          </td>
          <td style="text-align:right;">${statusBadge(bd.feasibility)}</td>
        </tr></table>
      </td>
    </tr>${rows}
  </table>`;
}

// -------------------- unmet ASB section --------------------
function unmetAsbsBlock() {
  const unmet = diag.unmetAsbs ?? [];
  if (unmet.length === 0) return "";
  const rows = unmet.map(u => `<tr>
    <td style="padding:6px 10px;border:1px solid #f4c4c4;font-size:12px;">${esc(u.reservationId)}</td>
    <td style="padding:6px 10px;border:1px solid #f4c4c4;font-size:12px;"><code>${esc(u.identifier)}</code></td>
    <td style="padding:6px 10px;border:1px solid #f4c4c4;font-size:12px;color:#c0392b;">${esc(u.reason)}</td>
  </tr>`).join("");
  return `<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-bottom:24px;border:2px solid #e74c3c;border-radius:6px;overflow:hidden;background:#fff7f6;">
    <tr><td style="padding:14px 16px;background:#fdecea;">
      <div style="font-size:14px;font-weight:700;color:#c0392b;font-family:Arial,sans-serif;">⚠ Unmet Anschlussbuchungen</div>
      <div style="font-size:12px;color:#7d3c98;margin-top:4px;">The following reservations requested ASB but could not be bound to their previous room. Please review and assign manually.</div>
    </td></tr>
    <tr><td style="padding:0 12px 12px 12px;">
      <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-top:8px;">
        <tr style="background:#fdecea;">
          <th style="padding:6px 10px;border:1px solid #f4c4c4;font-size:11px;text-align:left;">Reservation</th>
          <th style="padding:6px 10px;border:1px solid #f4c4c4;font-size:11px;text-align:left;">Requested ASB</th>
          <th style="padding:6px 10px;border:1px solid #f4c4c4;font-size:11px;text-align:left;">Reason</th>
        </tr>${rows}
      </table>
    </td></tr>
  </table>`;
}

// -------------------- summary bar --------------------
const assigned   = reservations.filter(r => r.assignment).length;
const unassigned = reservations.length - assigned;
const summaryBar = `<table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin-bottom:28px;background:#1a1a2e;border-radius:6px;overflow:hidden;">
  <tr><td style="padding:20px 24px;">
    <div style="color:#fff;font-size:13px;letter-spacing:1px;text-transform:uppercase;margin-bottom:6px;opacity:0.7;">Room Allocation Report</div>
    <div style="color:#fff;font-size:28px;font-weight:700;margin-bottom:16px;">Grand Total Score: ${totalScore >= 0 ? "+" : ""}${totalScore}</div>
    <table cellpadding="0" cellspacing="0"><tr>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Total</div><div style="color:#fff;font-size:20px;font-weight:700;">${reservations.length}</div></td>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Assigned</div><div style="color:#2ecc71;font-size:20px;font-weight:700;">${assigned}</div></td>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Unassigned</div><div style="color:${unassigned > 0 ? "#e74c3c" : "#2ecc71"};font-size:20px;font-weight:700;">${unassigned}</div></td>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Pre-assigned</div><div style="color:#fff;font-size:20px;font-weight:700;">${diag.preAssignedCount ?? 0}</div></td>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Unmet ASBs</div><div style="color:${(diag.unmetAsbs?.length ?? 0) > 0 ? "#e74c3c" : "#2ecc71"};font-size:20px;font-weight:700;">${diag.unmetAsbs?.length ?? 0}</div></td>
      <td style="padding-right:20px;"><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Group Proximity</div><div style="color:#fff;font-size:20px;font-weight:700;">${global.bookingGroupProximity ?? 0}</div></td>
      <td><div style="color:#aaa;font-size:11px;text-transform:uppercase;">Optional Upgrade</div><div style="color:${optionalUpgradeAllowed ? "#2ecc71" : "#e74c3c"};font-size:20px;font-weight:700;">${optionalUpgradeAllowed ? "✅ Allowed" : "❌ Disabled"}</div></td>
    </tr></table>
  </td></tr></table>`;

const cards = reservations.map((res, i) => reservationCard(res, i)).join("");
const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Room Allocation Report</title></head>
<body style="margin:0;padding:0;background:#f0f2f5;font-family:Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f2f5;"><tr><td align="center" style="padding:24px 12px;">
    <table width="700" cellpadding="0" cellspacing="0" style="max-width:700px;width:100%;">
      <tr><td>${summaryBar}</td></tr>
      <tr><td>${unmetAsbsBlock()}</td></tr>
      <tr><td>${cards}</td></tr>
      <tr><td style="padding:16px 0;text-align:center;font-size:11px;color:#999;">Generated by Room Allocation Optimizer · v2 · Scores reflect the combined objective function</td></tr>
    </table>
  </td></tr></table>
</body></html>`;

return [{ json: { html } }];

const reservations = $input.first().json.reservations;
function cleanString(str) { if (!str) return ''; return str.replace(/"/g, '').replace(/[\x00-\x1F\x7F]/g, '').trim(); }
function toTitleCase(str) { return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase(); }
const output = reservations.filter(r => r.assignment !== null).map(r => {
  const parts = [];
  const allSatisfied = [...(r.breakdown?.critical?.satisfied || []), ...(r.breakdown?.preference?.satisfied || [])];
  if (allSatisfied.length > 0) parts.push('Preferences satisfied: ' + allSatisfied.map(toTitleCase).join(', '));
  const upgrade = r.breakdown?.upgrade;
  if (upgrade?.applied) {
    const bookedType = upgrade.rationale?.bookedType || r.roomTypeBooked;
    const assignedType = upgrade.rationale?.assignedType || r.assignment?.unitGroupId;
    const upgradeAction = r.aiRequests?.allowedActions?.find(a => a.action && a.action.toLowerCase().includes('upgrade'));
    const mode = upgradeAction?.mode === 'FORCED' ? 'Forced' : 'Optional';
    parts.push('Upgrade [' + mode + ']: ' + bookedType + ' -> ' + assignedType);
  }
  if (parts.length === 0) return null;
  const existingComment = cleanString(r.comment);
  const agentNote = parts.join('\\n');
  const mergedComment = existingComment ? existingComment + '\\nRoomAllocationAgent: ' + agentNote : 'RoomAllocationAgent: ' + agentNote;
  return { json: { id: r.reservationId, mergedComment } };
}).filter(Boolean);
return output;

const reservations = $input.first().json.reservations;
const output = reservations.filter(r => r.assignment !== null).map(r => ({ json: { id: r.id, mergedComment: '' } }));
return output;
